var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"콜록, 콜록...!","JPN":"ゲホッ、ゲホッ……！","ENG":"*Cough* *Cough...!*","TWN":"咳、咳……！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"뭐하는 거지?","JPN":"何をしてるんだ？","ENG":"What are you doing?","TWN":"你在做什麼？"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"버번이란 걸 마셔보고 있었어요. 언니가 좋아하던 거라서 궁금했거든요.","JPN":"バーボンというものを飲んでいました。お姉ちゃんが好きだったので、ずっと気になっていて。","ENG":"I was trying something called bourbon. My sister used to like it, so I was curious.","TWN":"我在試著喝一種叫做波本的東西。因為姐姐以前很喜歡，所以我有點好奇。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"버번?","JPN":"バーボン？","ENG":"Bourbon?","TWN":"波本？"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"엘크 트레이스 15년산이다. 진한 오크 풍미가 매력이지.","JPN":"エルクトレース、15年だ。濃いオークの風味が魅力だな。","ENG":"Elk Trace, aged for fifteen years. The deep oak notes are the charm.","TWN":"是艾爾克崔斯15年產，濃厚的橡木風味很有魅力。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"무슨 말인지 모르겠군. 애초에 난 술을 마셔본 적도 없어.","JPN":"何のことだかさっぱりだ。そもそも私は酒を飲んだこともない。","ENG":"I have no idea what that means. I've never even tried alcohol in the first place.","TWN":"……我聽不太懂你在說什麼，我從來沒喝過酒。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아나필리스엔 증류라는 개념도 없던 건가?","JPN":"アナピリスには蒸留という概念がなかったのか？","ENG":"Did Anapilis not even have the concept of distillation?","TWN":"難道阿納菲莉絲沒有蒸餾這種概念嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"과일을 익히면 술이 된다는 건 알고 있지만, 별로 좋아하진 않아.","JPN":"果物を熟成させるとアルコールになることは知っているが、あまり好きではない。","ENG":"I know fruit becomes alcohol when it ripens, but I never cared for it much.","TWN":"我知道水果熟成之後會變成酒，但我並不喜歡。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이해가 안되는군.","JPN":"理解できないな。","ENG":"Unbelievable.","TWN":"真難理解。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"술맛을 모르는 나는... 대체 무슨 재미로 살았던 거지?","JPN":"酒の味が分からない私は……何を人生の楽しみにしていたんだ？","ENG":"What did I even do for fun... without knowing the taste of liquor?","TWN":"不知道酒味的人……活著到底有什麼樂趣呢？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"버섯을 키웠어. 선조들과의 교감을 명분으로 영감을 주는 버섯들을 사람들과 나눠먹었지.","JPN":"キノコなら栽培したぞ。先祖との交感を口実に、インスピレーションをくれるキノコをみんなで食べたものだ。","ENG":"I grew mushrooms instead. Under the pretense of communing with our ancestors, I shared inspiration-giving mushrooms with people.","TWN":"我以前種蘑菇。以和先祖交流為名，與人分享能帶來靈感的蘑菇。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"약쟁이였나. 나보다 더한 녀석이었군.","JPN":"薬物中毒者か。私よりも質が悪いじゃないか。","ENG":"So a junkie? That's worse than me, apparently.","TWN":"原來是癮君子啊，看來你比我還誇張。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"원하면 말해. 그림 그리는 데 영감을 줄 거다.","JPN":"欲しければ言え。絵を描く時も役に立つだろう。","ENG":"Tell me if you want some. It helps with painting.","TWN":"有興趣的話可以試試，對作畫會有幫助喔。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"...나중에. 지금은 꼬맹이도 보고 있으니까.","JPN":"……後でな。今はガキの目もある。","ENG":"...Maybe later. There's a kid watching right now.","TWN":"……之後再說吧，現在還有小孩子在看呢。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"헤헤, 저도 먹어보고 싶은데요? 버섯.","JPN":"へへ、そのキノコ、私も食べてみたいです。","ENG":"Hehe. I want to try some too. Mushrooms.","TWN":"嘿嘿，我也想試試那種蘑菇。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"꼬마는 안돼. 자제력을 잃으면 무슨 난동을 피울지 모르니까.","JPN":"ガキはだめだ。自制心を失ったらどんな騒ぎを起こすか分からないからな。","ENG":"No. Not for children. If you lose control, there's no telling what kind of trouble you'd cause.","TWN":"小孩子不行。如果失去自制力，不知道會鬧出什麼事。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"히잉-","JPN":"ふえん……","ENG":"Aww...","TWN":"嗚－"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"그럼 저는요?","JPN":"私ならどうですか？","ENG":"Then what about me?","TWN":"那我呢？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"...세계의 의지가 버섯에 취하면, 세상이 아주 볼만해지겠군.","JPN":"……世界の意志がキノコに酔うなんて、見ものだな。","ENG":"...If the Will of the World got drunk on mushrooms, the results would certainly be something to see.","TWN":"……要是世界的意志陶醉在蘑菇中，那畫面肯定很精彩。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"궁금하네. 먹여볼까?","JPN":"気になるな。食べさせてみるか？","ENG":"Now I'm curious. Should I let her try it?","TWN":"我有點好奇呢。要不要讓她試試？"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_PRIDE"},"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"네 동생 아니라고 막말하기는.","JPN":"自分の妹じゃないからって適当なこと言うな。","ENG":"Easy for you to say when she isn't your sister.","TWN":"不要不是你妹妹就隨便亂說耶。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_PRIDE"},"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아, 맞아. 아우드라 씨. 지난 번에 그 이야기 이어서 해주세요.","JPN":"あ、そうだ。アウドラさん。この前の話、続きを聞かせてください。","ENG":"Oh, right. Audra, please continue the story from last time.","TWN":"啊，對了。奧德拉，可以繼續說上次那個故事嗎？"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"작은 왕이란 소녀는 결국 어떻게 됐나요?","JPN":"小さい王っていう女の子は結局どうなったんですか？","ENG":"What happened to the girl called the little queen in the end?","TWN":"那位叫小王的少女，最後怎麼樣了？"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"...새로운 대적자 모르가나는 마왕 타기리온을 무찌르고 그 신위를 이을 자격을 갖췄지만 아무 일도 일어나지 않았어요.","JPN":"……新しい敵対者モルガナは魔王タギリオンを倒し、その神威を引き継ぐ資格を揃えたけど、何も起きませんでした。","ENG":"...The new Antagonist, Morgana, defeated Demon Lord Thagirion and earned the right to inherit that divine authority. But nothing happened afterward.","TWN":"……成為新任敵對者的莫甘娜，擊敗了魔王塔基里翁、取得了繼承神位的資格，但卻什麼都沒有發生。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"외세계에서 온 그 남자 덕에, 더는 누구도 원치 않는 운명을 짊어질 필요가 없어졌으니까요.","JPN":"外の世界から来た男のおかげで、もう誰も望まぬ運命を背負う必要がなくなったからです。","ENG":"Thanks to the man who came from beyond the world, no one needed to shoulder a fate they never wished for again.","TWN":"多虧來自外界的那名男子，讓所有人都不需要再背負不願意的命運。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"마왕이 없어진 세상에서 대적자는 어떻게 되는 거죠?","JPN":"魔王がいなくなった世界で、敵対者はどうなるんですか？","ENG":"Then what happens to an Antagonist in a world without a Demon Lord?","TWN":"在沒有魔王的世界裡，敵對者會變成什麼？"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"현재를 위협하는 존재가 사라졌으니, 세상은 서서히 영웅을 잊게 되겠죠.","JPN":"現在を脅かす存在が消えたので、世界は徐々に英雄のことを忘れていくでしょう。","ENG":"Since the threat to the present has disappeared, the world will slowly forget its hero.","TWN":"既然威脅消失了，世界也會逐漸遺忘英雄吧。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"하지만 그것이 끝을 의미하는 건 아녜요. 언젠가 다가올 미래에 새로운 위협이 나타나면 다시 그녀를 필요로 하게 될 테니까.","JPN":"でも、それが完全な終わりではありません。いつか来る未来に新たな脅威が現れたら、彼女は再び必要とされるでしょう。","ENG":"But that doesn't mean it's the end. If a new threat appears in the distant future, she will be needed again.","TWN":"但那並不代表終結。當未來再次出現新的威脅時，眾人仍會需要她。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그 위협은... 또다른 마왕인가?","JPN":"その脅威とは……別の魔王のことか？","ENG":"A threat... from another Demon Lord?","TWN":"那個威脅……會是另一個魔王嗎？"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"그건 아무도 몰라요. 모든 존재가 운명으로부터 해방된 순간, 정해진 미래라는 것도 사라졌으니까요.","JPN":"それは誰にも分かりません。すべての存在が運命から解放された瞬間、定められた未来というものも消えましたから。","ENG":"No one knows. The moment all beings were freed from fate, the notion of a predetermined future vanished as well.","TWN":"沒有人知道。當所有存在都從命運中解放的那一刻起，既定的未來也一同消失了。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"하지만 어딘가에 심연이 존재하는 한, 이 낙원에도 영원한 평화라는 건 없을 테죠.","JPN":"でもどこかに深淵が存在する限り、この楽園にも永遠の平和はないでしょう。","ENG":"However, so long as the abyss exists somewhere, even the Promised Land can't remain in eternal peace.","TWN":"但只要某處仍存在著深淵，這個樂園也不會擁有永遠的和平。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"다행이군. 사람의 마음은 간사해서, 지켜야 할 필요가 있을 때만 그 소중함을 아는 법이니까.","JPN":"それはよかった。人の心とは身勝手なもので、守らなければならない状況になって初めて、その大切さに気づくものだからな。","ENG":"That's a relief. People are fickle, only recognizing the value of what they have when there's something worth protecting.","TWN":"這樣也好。人心本就狡猾，只有在需要守護的時候才會明白其珍貴。"},"stage":{"bg":"CLUB1","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};